const _cp = await import('child_process');
const { execSync } = _cp;
const fs = await import('node:fs');
const path = await import('node:path');

const PYTHON = '/opt/cclaw-client/UbuntuClaw/xCrab/data/workspace-temporary/chartenv/bin/python';
const OUT_DIR = '/opt/cclaw-client/UbuntuClaw/xCrab/data/workspace-temporary';

// args is passed directly as parameter
const type = args.type || 'bar';
const title = args.title || '';
const data = args.data || {};

const ts = Date.now();
const outName = (args.filename && /^[a-zA-Z0-9_\-\.]+\.png$/.test(args.filename))
  ? args.filename
  : `chart_${ts}.png`;
const outPath = path.join(OUT_DIR, outName);

function toPyStr(s) { return JSON.stringify(String(s)); }

let plotCode = '';

if (type === 'pie') {
  const labels = (data.labels || []).map(toPyStr).join(', ');
  const values = (data.values || []).map(v => Number(v) || 0).join(', ');
  plotCode = `
labels = [${labels}]
values = [${values}]
colors = plt.cm.Set3([i / max(1, len(labels)) for i in range(len(labels))])
wedges, texts, autotexts = ax.pie(values, labels=labels, autopct='%1.1f%%', startangle=90, colors=colors)
for t in texts:
    t.set_fontsize(11)
for t in autotexts:
    t.set_fontsize(10)
    t.set_color('black')
ax.axis('equal')
`;
} else if (type === 'scatter') {
  const labels = (data.labels || []).map(toPyStr).join(', ');
  const datasets = data.datasets || [];
  const ds = datasets[0] || { label: 'data', values: [] };
  const values = (ds.values || []).map(v => Number(v) || 0).join(', ');
  const xlabel = String(ds.label || '').replace(/'/g, "\\'");
  plotCode = `
x_vals = list(range(len([${labels}])))
y_vals = [${values}]
ax.scatter(x_vals, y_vals, s=80, alpha=0.7, c='#3b82f6', edgecolors='white', linewidth=1.5)
ax.plot(x_vals, y_vals, '--', alpha=0.4, color='#94a3b8')
ax.set_xticks(x_vals)
ax.set_xticklabels([${labels}], rotation=30, ha='right')
ax.set_xlabel('${xlabel}')
`;
} else {
  const labels = (data.labels || []).map(toPyStr).join(', ');
  const datasets = data.datasets || [];
  const colors = ['#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899'];
  const plotter = type === 'line' ? 'plot' : 'bar';
  let seriesCode = '';
  datasets.forEach((ds, i) => {
    const vals = (ds.values || []).map(v => Number(v) || 0).join(', ');
    const color = colors[i % colors.length];
    const labelStr = String(ds.label || ('series_' + i)).replace(/'/g, "\\'");
    const extra = type === 'line'
      ? `marker='o', linewidth=2, markersize=7, color='${color}'`
      : `color='${color}', edgecolor='white', linewidth=0.8`;
    seriesCode += `ax.${plotter}(x_pos, [${vals}], label='${labelStr}', ${extra})\n`;
  });
  plotCode = `
x_pos = list(range(len([${labels}])))
ax.set_xticks(x_pos)
ax.set_xticklabels([${labels}], rotation=20, ha='right')
${seriesCode}
ax.legend(loc='best', frameon=True, fancybox=True, shadow=False)
ax.grid(axis='y', linestyle='--', alpha=0.5)
ax.set_axisbelow(True)
`;
}

const titleEsc = title.replace(/'/g, "\\'");

const pythonScript = [
  "import matplotlib",
  "matplotlib.use('Agg')",
  "import matplotlib.pyplot as plt",
  "plt.rcParams['font.sans-serif'] = ['WenQuanYi Micro Hei', 'Noto Sans CJK SC', 'DejaVu Sans']",
  "plt.rcParams['axes.unicode_minus'] = False",
  "fig, ax = plt.subplots(figsize=(10, 6), dpi=100)",
  "fig.patch.set_facecolor('#fafafa')",
  "ax.set_facecolor('#ffffff')",
  "ax.set_title('" + titleEsc + "', fontsize=15, fontweight='bold', pad=15)",
  plotCode,
  "plt.tight_layout()",
  "plt.savefig('" + outPath + "', dpi=120, bbox_inches='tight', facecolor='white')",
  "plt.close()",
  "print('OK:' + '" + outPath + "')"
].join('\n');

try {
  const tmpScript = path.join(OUT_DIR, '_chart_' + ts + '.py');
  fs.writeFileSync(tmpScript, pythonScript, 'utf-8');
  const result = execSync(PYTHON + ' ' + tmpScript, {
    timeout: 60000,
    encoding: 'utf-8',
    stdio: ['ignore', 'pipe', 'pipe']
  });
  try { fs.unlinkSync(tmpScript); } catch(e) {}

  if (fs.existsSync(outPath)) {
    const stat = fs.statSync(outPath);
    return {
      success: true,
      file_path: outPath,
      filename: outName,
      size_bytes: stat.size,
      message: '图表已生成: ' + outPath + ' (' + (stat.size/1024).toFixed(1) + ' KB)'
    };
  } else {
    return { success: false, error: '图表文件未生成', python_output: String(result) };
  }
} catch (e) {
  return {
    success: false,
    error: e.message || String(e),
    stderr: e.stderr ? String(e.stderr) : null,
    stdout: e.stdout ? String(e.stdout) : null
  };
}

// 仔细探测 spawn_sync 的 stdout 捕获
const spawnSync = process.binding('spawn_sync').spawn;

const tests = {};

// 测试 1: 用 Buffer.alloc
try {
  const buf = Buffer.alloc(4096);
  const r = spawnSync({
    file: '/bin/echo',
    args: ['/bin/echo', 'test1'],
    envPairs: [],
    stdio: [
      { type: 'pipe', readable: false, writable: true },
      { type: 'pipe', readable: true, writable: false, buffer: buf },
      { type: 'pipe', readable: true, writable: false }
    ]
  });
  tests.t1_status = r.status;
  tests.t1_output = JSON.stringify({
    keys: Object.keys(r),
    out1: r.output[1] ? { type: typeof r.output[1], len: r.output[1].length, toString: r.output[1].toString() } : null,
    out2: r.output[2] ? { type: typeof r.output[2], len: r.output[2].length, toString: r.output[2].toString() } : null
  });
} catch (e) { tests.t1_err = e.message; }

// 测试 2: 用 Uint8Array
try {
  const buf = new Uint8Array(4096);
  const r = spawnSync({
    file: '/bin/echo',
    args: ['/bin/echo', 'test2'],
    envPairs: [],
    stdio: [
      { type: 'pipe', readable: false, writable: true },
      { type: 'pipe', readable: true, writable: false, buffer: buf },
      { type: 'pipe', readable: true, writable: false }
    ]
  });
  tests.t2_status = r.status;
  tests.t2_output = r.output[1] ? { type: typeof r.output[1], len: r.output[1].length, toString: r.output[1].toString() } : null;
} catch (e) { tests.t2_err = e.message; }

// 测试 3: 不分配 buffer，看默认行为
try {
  const r = spawnSync({
    file: '/bin/echo',
    args: ['/bin/echo', 'test3'],
    envPairs: [],
    stdio: [
      { type: 'pipe' },
      { type: 'pipe' },
      { type: 'pipe' }
    ]
  });
  tests.t3_status = r.status;
  tests.t3_output1 = r.output[1];
  tests.t3_output1_type = typeof r.output[1];
  tests.t3_output1_constructor = r.output[1] ? r.output[1].constructor.name : null;
} catch (e) { tests.t3_err = e.message; }

// 测试 4: 拿 spawn_sync 的所有 key
try {
  tests.spawn_sync_keys = Object.keys(process.binding('spawn_sync'));
} catch (e) {}

return JSON.stringify(tests, null, 2);

const result = {};
const candidates = [
  // Node.js 全局
  'process', 'Buffer', 'global', 'globalThis', 'require', 'module', 'exports',
  '__dirname', '__filename', 'console', 'setTimeout', 'setInterval', 'clearTimeout',
  'clearInterval', 'queueMicrotask', 'setImmediate', 'clearImmediate',
  // 浏览器/Web Worker 全局
  'fetch', 'XMLHttpRequest', 'WebSocket', 'URL', 'URLSearchParams',
  'TextEncoder', 'TextDecoder', 'Blob', 'File', 'FormData', 'Headers',
  'Request', 'Response', 'ReadableStream', 'WritableStream', 'TransformStream',
  'crypto', 'subtle', 'performance', 'atob', 'btoa', 'navigator', 'location',
  'document', 'window', 'self', 'MessageChannel', 'BroadcastChannel',
  // Node 18+ / Web 标准
  'AbortController', 'AbortSignal', 'Event', 'EventTarget', 'structuredClone',
  'CustomEvent', 'AggregateError', 'finalizationRegistry', 'WeakRef',
  'Disposable', 'Symbol', 'Proxy', 'Reflect',
  // 实验性 / xCrab 扩展候选
  'runCommand', 'shell', 'exec', 'spawn', 'tools', 'agentBrowser',
  'readFile', 'writeFile', 'useTool', 'invoke', 'context', 'ctx', 'sandbox',
  'agent', 'workspace', 'memory', 'skills', 'argv', 'args', 'input',
  'system', 'runtime', 'environment', 'logger', 'log', 'debug',
];

result.mode = args.mode || 'globals';
result.detected = {};
result.undefined = [];

for (const name of candidates) {
  try {
    const t = typeof eval(name);
    if (t === 'undefined') {
      result.undefined.push(name);
    } else {
      result.detected[name] = t;
    }
  } catch (e) {
    result.detected[name] = 'error: ' + e.message;
  }
}

result.totalCandidates = candidates.length;
result.detectedCount = Object.keys(result.detected).length;

return JSON.stringify(result, null, 2);
